import uuid
import pytest

@pytest.mark.parametrize("amount,expected_codes", [
    ("500.00",   (200, 201)),
    ("0.00",     (422,)),
    ("-1.00",    (422,)),
    ("50001.00", (422,)),
])
def test_billpay_decision_table_valid_vs_invalid_amount_with_idempotency_key(
    api_client,
    registered_biller,
    amount,
    expected_codes
):
    payload = {
        "biller_id": registered_biller,
        "amount": amount,
        "currency": "USD"
    }
    headers = {"Idempotency-Key": str(uuid.uuid4())}

    resp = api_client.post("/billpay", json=payload, headers=headers)

    assert resp.status_code in expected_codes, (
        f"amount={amount}: expected {expected_codes}, got {resp.status_code}"
    )
